
'use client';

import { useState, useEffect, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { useToast } from '@/hooks/use-toast';
import { Bluetooth, BluetoothConnected, BluetoothSearching, Loader2, SprayCan, XCircle } from 'lucide-react';

interface DeviceConnectorProps {
  csvData: string | null;
}

// Standard BLE Service for device information
const SERVICE_UUID = '4fafc201-1fb5-459e-8fcc-c5c9c331914b';
const CHARACTERISTIC_UUID = 'beb5483e-36e1-4688-b7f5-ea07361b26a8';

export default function DeviceConnector({ csvData }: DeviceConnectorProps) {
  const [isSupported, setIsSupported] = useState(true);
  const [status, setStatus] = useState<'disconnected' | 'connecting' | 'connected' | 'error'>('disconnected');
  const [deviceName, setDeviceName] = useState<string | null>(null);
  const [characteristic, setCharacteristic] = useState<BluetoothRemoteGATTCharacteristic | null>(null);
  const [isSpraying, setIsSpraying] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    if (typeof window !== 'undefined' && 'bluetooth' in navigator) {
      setIsSupported(true);
    } else {
      setIsSupported(false);
    }
  }, []);

  const handleConnect = useCallback(async () => {
    if (!('bluetooth' in navigator)) {
      toast({ variant: 'destructive', title: 'Web Bluetooth not supported' });
      return;
    }
    setStatus('connecting');
    try {
      const device = await navigator.bluetooth.requestDevice({
        acceptAllDevices: true,
        optionalServices: [SERVICE_UUID],
      });
      
      if (!device.gatt) {
          throw new Error("GATT server not available.");
      }

      const server = await device.gatt.connect();
      setDeviceName(device.name || 'Unknown Device');
      
      const service = await server.getPrimaryService(SERVICE_UUID);
      const char = await service.getCharacteristic(CHARACTERISTIC_UUID);
      setCharacteristic(char);
      setStatus('connected');
      toast({ title: 'Device Connected', description: `Successfully connected to ${device.name || 'Unknown Device'}.` });
    } catch (error: any) {
      console.error('BLE Connection failed:', error);
      // Don't show an error toast if the user simply cancels the device selection dialog.
      if (error.name !== 'NotFoundError') {
        toast({ variant: 'destructive', title: 'Connection Failed', description: error.message });
      }
      setStatus('error');
    }
  }, [toast]);

  const handleSpray = async () => {
    if (!characteristic || !csvData) {
      toast({ variant: 'destructive', title: 'Cannot Spray', description: 'Device not connected or no analysis data available.' });
      return;
    }
    setIsSpraying(true);
    try {
      const encoder = new TextEncoder();
      const data = encoder.encode(csvData);
      await characteristic.writeValue(data);
      toast({ title: 'Spray command sent!', description: 'Your device should now be dispensing the treatment.' });
    } catch (error: any) {
      console.error('Failed to send spray command:', error);
      toast({ variant: 'destructive', title: 'Spray Failed', description: error.message });
    } finally {
      setIsSpraying(false);
    }
  };

  const statusInfo = {
    disconnected: { icon: Bluetooth, text: 'Connect to your Econix device to dispense treatment.', color: 'text-muted-foreground' },
    connecting: { icon: Loader2, text: 'Searching for devices...', color: 'text-blue-500 animate-spin' },
    connected: { icon: BluetoothConnected, text: `Connected to ${deviceName}. Ready to spray.`, color: 'text-green-500' },
    error: { icon: XCircle, text: 'Connection failed. Please try again.', color: 'text-destructive' },
  };

  const { icon: StatusIcon, text: statusText, color: statusColor } = statusInfo[status];

  if (!isSupported) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Device Control</CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-destructive">Web Bluetooth is not supported on this browser. Please use a compatible browser like Chrome on Desktop or Android.</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Device Control</CardTitle>
        <CardDescription>Connect to your ESP32-powered sprayer to apply the treatment.</CardDescription>
      </CardHeader>
      <CardContent className="space-y-4 text-center">
        <div className={`flex items-center justify-center gap-2 ${statusColor}`}>
          <StatusIcon className="h-5 w-5" />
          <p>{statusText}</p>
        </div>
        <div className="flex justify-center gap-4">
            {status !== 'connected' && (
                <Button onClick={handleConnect} disabled={status === 'connecting'}>
                    {status === 'connecting' ? <BluetoothSearching className="mr-2 h-4 w-4"/> : <Bluetooth className="mr-2 h-4 w-4" /> }
                    Connect Device
                </Button>
            )}
            {status === 'connected' && (
                <Button onClick={handleSpray} disabled={isSpraying || !csvData}>
                    {isSpraying ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <SprayCan className="mr-2 h-4 w-4" />}
                    {isSpraying ? 'Spraying...' : 'Spray Treatment'}
                </Button>
            )}
        </div>
      </CardContent>
    </Card>
  );
}
